#include<bits/stdc++.h>
using namespace std;
struct node
{
    int d,m;
    bool operator<(const node&b)const
    {
        return d<b.d;
    }
}a[100010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].d,&a[i].m);
    }
    sort(a+1,a+1+n);
    priority_queue<int,vector<int>,greater<int>> q;
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        if(q.size()==a[i].d)
        {
            if(q.top()<a[i].m)
            {
                ans-=q.top();
                q.pop();
                q.push(a[i].m);
                ans+=a[i].m;
            }
        }
        else
        {
            ans+=a[i].m;
            q.push(a[i].m);
        }
    }
    printf("%lld",ans);
    return 0;
}
